// Lookup function - finds nearest grid to given lat/lng
function findHoodScore(lat, lng) {
    const grids = HS.g;
    let nearest = null;
    let minDist = Infinity;
    
    for (const g of grids) {
        const d = Math.pow(g[0] - lat, 2) + Math.pow(g[1] - lng, 2);
        if (d < minDist) {
            minDist = d;
            nearest = g;
        }
    }
    
    if (!nearest || minDist > 0.001) return null; // ~1km threshold
    
    return {
        score: nearest[2],
        grade: scoreToGrade(nearest[2]),
        city: HS.n[HS.c[nearest[3]]],
        distance: Math.sqrt(minDist) * 111 // rough km
    };
}

function scoreToGrade(s) {
    if (s >= 90) return 'A+';
    if (s >= 85) return 'A';
    if (s >= 80) return 'A-';
    if (s >= 75) return 'B+';
    if (s >= 70) return 'B';
    if (s >= 65) return 'B-';
    if (s >= 60) return 'C+';
    if (s >= 55) return 'C';
    if (s >= 50) return 'C-';
    if (s >= 45) return 'D+';
    if (s >= 40) return 'D';
    if (s >= 35) return 'D-';
    return 'F';
}
